operations.insert:
.recheck-pallet-btn {
  margin-left: 12px;
  min-height: 30px;
  padding: 0 12px;
  border-radius: 999px;
  border: 1px solid rgba(11, 92, 171, 0.22);
  background: #ffffff;
  color: #0b5cab;
  font-size: 13px;
  font-weight: 760;
  box-shadow: none;
  vertical-align: middle;
}

.recheck-pallet-btn:hover {
  transform: none;
  background: #eaf3fc;
}

function recheckCompletedPallet(palletId) {
  const rows = state.rows.filter((row) => row.palletId === palletId);
  if (rows.length === 0) {
    setStatus("This pallet is no longer available in the loaded data.", "warn");
    return;
  }

  pendingPalletConfirmation = "";
  hideWorkflowModal();
  setStatus("Re-check started for completed pallet " + palletId + ". Scan SKU/EAN codes again.", "info");
  startScanWorkflow(rows, palletId);
  queueFocusActiveInput();
}
